class ProductionAssetConfig:
    def __init__(self, chunkchildrecords=100, chunkonchangeof=''):
        self.chunkchildrecords = chunkchildrecords
        self.chunkonchangeof = chunkonchangeof

    def validate(self):
        if not isinstance(self.chunkchildrecords, int) or self.chunkchildrecords <= 0:
            raise ValueError("chunkchildrecords must be a positive integer.")
        if not isinstance(self.chunkonchangeof, str):
            raise ValueError("chunkonchangeof must be a string.")

def solve(*args):
    config = ProductionAssetConfig(*args)
    config.validate()
    return None
